const cb = $json.callback_query;
if (!cb) throw new Error('No callback_query');

const data = cb.data || '';

// EXPECT: approve::rowId OR reject::rowId
const [action, rowId] = data.split('::');

return [{
  json: {
    action: action,         // approve / reject
    rowId: rowId,           // actual row id
    chatId: String(cb.message.chat.id),
    messageId: cb.message.message_id,
    callbackQueryId: cb.id
  }
}];

if ($input.all().length > 1 && $input.itemIndex > 0) {
  return [];
}
// SAFE RSS ACCESS
const rssItems = $('Fetch Google News RSS').all();

if (!rssItems.length) {
  throw new Error('RSS data missing');
}

const xml = rssItems[0].json.data;


// GET USED ARTICLES SAFELY (WORKS EVEN IF SHEET EMPTY)
let usedTitles = [];

try {
  const usedItems = $('Read Used Articles').all();

  usedTitles = usedItems
    .map(item => item.json["Title"] || item.json["Title "] || "")
    .filter(Boolean)
    .map(t => t.toLowerCase().trim());

} catch (e) {
  usedTitles = [];
}


// EXTRACT RSS ITEMS
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
const items = [];
let match;

while ((match = itemRegex.exec(xml)) !== null) {
  items.push(match[1]);
}


// PARSE ARTICLES
const articles = items.slice(0, 10).map(item => {
  const title = (item.match(/<title>([\s\S]*?)<\/title>/) || [])[1] || '';
  const description = (item.match(/<description>([\s\S]*?)<\/description>/) || [])[1] || '';
  const pubDate = (item.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1] || '';
  const link = (item.match(/<link>([\s\S]*?)<\/link>/) || [])[1] || '';

  return {
    title: title
      .replace(/<!\[CDATA\[|\]\]>/g, '')
      .replace(/\s*-\s*[\w.]+\.(com|in|org|net|co\.in)$/i, '')
      .trim(),

    description: description
      .replace(/<!\[CDATA\[|\]\]>/g, '')
      .replace(/<[^>]+>/g, '')
      .trim(),

    pubDate: pubDate.trim(),
    link: link.trim()
  };
});


// REMOVE EMPTY TITLES
const validArticles = articles.filter(a => a.title.length > 5);


// REMOVE ALREADY USED ARTICLES
const unused = validArticles.filter(a =>
  !usedTitles.includes(a.title.toLowerCase().trim())
);


// HANDLE FULLY USED CASE
const pool = unused.length > 0 ? unused : validArticles;

if (pool.length === 0) {
  throw new Error('No valid articles found in RSS feed');
}


// RANDOM PICK
const randomIndex = Math.floor(Math.random() * pool.length);
const top = pool[randomIndex];


// EXTRA SAFETY CHECK
const isAlreadyUsed = usedTitles.includes(top.title.toLowerCase().trim());

if (isAlreadyUsed && unused.length > 0) {
  const fallback = unused[0];

  return [{
    json: {
      topic: fallback.title,
      description: fallback.description,
      pubDate: fallback.pubDate,
      link: fallback.link,
      unusedCount: unused.length,
      totalArticles: validArticles.length,
      usedCount: usedTitles.length,
      note: 'fallback used'
    }
  }];
}


// FINAL OUTPUT
return [{
  json: {
    topic: top.title,
    description: top.description,
    pubDate: top.pubDate,
    link: top.link,
    unusedCount: unused.length,
    totalArticles: validArticles.length,
    usedCount: usedTitles.length,
    note: 'random pick'
  }
}];

const raw = $json.output || $json.text || JSON.stringify($json);

// Nuclear clean all problematic characters
let clean = raw
  .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
  .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'")
  .replace(/\\n/g, ' ')
  .replace(/\\t/g, ' ')
  .replace(/\\r/g, ' ')
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Extract JSON object
const match = clean.match(/\{[\s\S]*\}/);
if (!match) {
  return [{
    json: {
      error: 'AI output invalid',
      rawOutput: raw
    }
  }];
}

// Fix any remaining smart quotes inside JSON strings
clean = clean.replace(/"\s*:\s*"([^"]*?)"/g, (m, p1) => {
  return m.replace(/[\u201C\u201D\u201E\u201F]/g, '\\"');
});

let parsed;
try {
  parsed = JSON.parse(clean);
} catch(e) {
  // Last resort — manually extract tweets using regex
  const tweetRegex = /"text"\s*:\s*"(.*?)(?<!\\)"/g;
  const hashRegex = /"hashtags"\s*:\s*"(.*?)(?<!\\)"/g;
  const styleRegex = /"style"\s*:\s*"(.*?)(?<!\\)"/g;

  const texts = [...clean.matchAll(/"text"\s*:\s*"([^"]+)"/g)].map(m => m[1]);
  const hashes = [...clean.matchAll(/"hashtags"\s*:\s*"([^"]+)"/g)].map(m => m[1]);
  const styles = [...clean.matchAll(/"style"\s*:\s*"([^"]+)"/g)].map(m => m[1]);

  if (texts.length === 0) throw new Error('Could not parse tweets: ' + e.message);

  parsed = {
    tweets: texts.map((text, i) => ({
      style: styles[i] || 'unknown',
      text: text,
      hashtags: hashes[i] || ''
    }))
  };
}

const topic = $('Process Article Extraction').first().json.topic;
const description = $('Process Article Extraction').first().json.description;

const times = ['08:00 IST', '10:00 IST', '12:00 IST', '14:00 IST', '16:00 IST'];

const now = new Date();
const istOffset = 5.5 * 60 * 60000;
const istNow = new Date(now.getTime() + istOffset);
const today = istNow.toISOString().split('T')[0];
const createdAtIST = istNow.toISOString().replace('Z', '+05:30');

const rows = parsed.tweets.map((tweet, index) => {
  const fullPost = tweet.text + ' ' + tweet.hashtags;
  const rowId = tweet.style + '_' + today + '_' + Date.now();

  const blocks = [
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: "*Tweet ready for approval*\n\n*Style:* " + tweet.style + "\n*Scheduled:* " + times[index] + "\n*Topic:* " + topic + "\n\n*Tweet:*\n" + tweet.text + "\n\n" + tweet.hashtags
      }
    },
    {
      type: "actions",
      block_id: rowId,
      elements: [
        {
          type: "button",
          text: { type: "plain_text", text: "Approve" },
          style: "primary",
          value: "approved",
          action_id: "approve_tweet"
        },
        {
          type: "button",
          text: { type: "plain_text", text: "Reject" },
          style: "danger",
          value: "rejected",
          action_id: "reject_tweet"
        }
      ]
    }
  ];

  return {
    json: {
      topic: topic,
      description: description,
      style: tweet.style,
      tweet: tweet.text,
      hashtags: tweet.hashtags,
      fullPost: fullPost,
      charCount: fullPost.length,
      scheduledTime: times[index],
      scheduledDate: today,
      status: 'Pending',
      createdAt: createdAtIST,
      rowId: rowId,
      slackBlocks: JSON.stringify(blocks)
    }
  };
});

return rows;
